css:
.loader {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #0284c7);
  background: linear-gradient(90deg,var(--loader-color, #0284c7),var(--loader-secondary-color, #7dd3fc)) 50%/0 100% no-repeat text;
  animation: l4 1.5s linear infinite;
}
.loader:before {
  content: "Loading";
}
@keyframes l4 {
  to{background-size: 120% 100%}
}
